pub fn register(registry: &mut ToolRegistry) {
    registry.register(copy::FsCopyTool);
    registry.register(create::FsCreateTool);
    registry.register(read::FsReadTool);
    registry.register(ls::FsLsTool);
    registry.register(write::FsWriteTool);
    registry.register(delete::FsDeleteTool);
    registry.register(move_file::FsMoveTool);
    registry.register(mkdir::FsMkdirTool);
    registry.register(patch::FsPatchTool);
}

pub fn register(registry: &mut ToolRegistry) {
    registry.register(stage_paths::GitStagePathsTool);
    registry.register(commit::GitCommitTool);
    registry.register(push::GitPushTool);
}

pub fn register(registry: &mut ToolRegistry) {
    registry.register(spawn::ProcSpawnTool);
    registry.register(which::ProcWhichTool);
}

pub fn register(registry: &mut ToolRegistry) {
    registry.register(now::TimeNowTool);
    registry.register(sleep::TimeSleepTool);
}

pub fn register_builtins(registry: &mut ToolRegistry) {
    fs::register(registry);
    git::register(registry);
    github::register(registry);
    orbit::register(registry);
    proc::register(registry);
    time::register(registry);
    net::register(registry);
}

fn load_external_tools(store: &Store, registry: &mut ToolRegistry) -> Result<(), OrbitError> {
    let stored_tools = store.list_tools()?;
    for tool in stored_tools {
        if !tool.builtin && tool.enabled && !registry.has(&tool.name) {
            registry.register(ExternalTool {
                name: tool.name,
                path: tool.path,
                description: tool.description,
                parameters: tool.parameters,
            });
        }
    }
    Ok(())
}

fn default() -> Self {
        let mut registry = Self::new();
        let _ = registry.register(Arc::new(crate::providers::mock_agent::MockAgentFactory));
        let _ = registry.register(Arc::new(crate::providers::codex::CodexFactory));
        let _ = registry.register(Arc::new(crate::providers::claude::ClaudeFactory));
        let _ = registry.register(Arc::new(crate::providers::gemini::GeminiFactory));
        let _ = registry.register(Arc::new(crate::providers::ollama::OllamaFactory));
        registry
    }

pub fn register_builtins(&mut self) {
        let _ = self.register(CliCommandExecutor);
        let _ = self.register(AutomationExecutor);
        let _ = self.register(crate::activity_job::OrbitToolCallExecutor);
    }

